var e=[{id:`L2_1`,type:`dialog`,speaker:`OGRE2_NPC_NULL_NULL`,text:{KOREA:`크르르......`,JPN:`ガルル……`,ENG:`Grrr...`,TWN:`吼喔喔……`},stage:{bg:`SUMMER_BEACH_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`OGRE1_NPC_NULL_NULL`,text:{KOREA:`크으으......`,JPN:`グルル……`,ENG:`Khhhhkkk...`,TWN:`吼……`},stage:{bg:`SUMMER_BEACH_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`괘, 괜찮아, 둘 다?`,JPN:`二人とも、だ、大丈夫？`,ENG:`Y-you two, are you okay?`,TWN:`你們兩個沒、沒事吧？`},stage:{bg:`SUMMER_BEACH_NIGHT`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`뭐야? 어디서 공격이 날아온 거야?`,JPN:`どこから攻撃されてるの？`,ENG:`What was that? Where did that attack come from?`,TWN:`怎麼回事？是從哪裡過來的攻擊？`},stage:{bg:`SUMMER_BEACH_NIGHT`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`크큭, 이 애송이들. 내가 이 정도로 포기한 줄 알았냐?`,JPN:`くっ、このガキどもが。俺がこの程度で諦めると思ったのか？`,ENG:`Heh heh, you punks. You thought I gave up, didn't you?`,TWN:`哼，小鬼們，你們以為我會就這樣放棄嗎？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`적당히 상대하고 타깃만 데려가려 했지만......`,JPN:`適当に相手して、ターゲットだけ連れ去ろうと思ったが……`,ENG:`Originally, I was just going to leave quietly with the target,`,TWN:`我本只想隨便跟你們玩玩，帶走目標就好……`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`이렇게 된 이상 수단방법을 가리지 않고 모조리 쓸어버리겠다!`,JPN:`こうなった以上、どんな手を使ってでも一掃してやる！`,ENG:`but not anymore—I'm going to wipe you all out!`,TWN:`但事到如今，我不會在管什麼手段了，我要把你們全都解決掉！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`대, 대장님 살아계셨습니까?`,JPN:`た、隊長。無事だったんですね！`,ENG:`C-Captain, I didn't know you were alive.`,TWN:`隊、隊長，你還活著？`},stage:{bg:`SUMMER_BEACH_NIGHT`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`당연하지! 최종전 보스가 한 번 쓰러지고 끝나는 거 봤어?`,JPN:`当たり前だ！　ラスボスが一回倒されて終わったところを見たことあるのか？`,ENG:`Are you kidding me? The last boss never goes away after just a single fight.`,TWN:`當然！有那種被打倒一次就死掉的最終BOSS嗎？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`원래 보스는 언제나 비장의 수를 남겨두는 법이다!`,JPN:`元々ボスは常に切り札を最後まで残しておくものなのだ！`,ENG:`He always comes back with surprises!`,TWN:`自古以來，BOSS都會留一招殺手鐧！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`대단하십니다! 그야말로 악당 그 자체시군요!`,JPN:`素晴らしいです。悪党の鑑です！`,ENG:`Incredible, sir! You're the manifestation of evil itself!`,TWN:`了不起！不愧是是壞人本色！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`혹시 방금 그 번뜩이는 레이저도 대장님이 말씀하신 비장의 수인 겁니까?`,JPN:`さっき光ったレーザーが隊長の切り札ですか？`,ENG:`Is that laser beam that just flashed also one of your surprises?`,TWN:`剛才那個雷射光束也是隊長說的殺手鐧嗎？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`그래, 이건 정말 마지막까지 쓰지 않으려고 했지만 어쩔 수 없지.`,JPN:`そうだ。これは最後まで使うつもりはなかったが仕方ない。`,ENG:`Yes, I really didn't want to use it, but I had no choice.`,TWN:`沒錯，我本來不到最後不打算用的，但是沒辦法了。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`가라! 이 순간을 위해 노후 연금까지 탈탈 털어 비밀 경매장에서 구입해 둔 비장의 거대 결전 병기!`,JPN:`行け！　この瞬間のために老後の年金まで叩いて闇オークションで購入した秘蔵の巨大決戦兵器！`,ENG:`Now, go! I spent my whole pension pot to buy this massive weapon of destruction from a secret auction house.`,TWN:`去吧！為了這個瞬間，我把我的養老金都砸了下去，在競標標下的巨大決戰兵器！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`골드-아머-프라임! 출격이다!`,JPN:`ゴールド・アーマー・プライム！　出撃だ！`,ENG:`Here goes Gold Armor Prime!`,TWN:`黃金·裝甲·優質！出擊！`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`GAP_GOLD_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_SUMMER_NULL`,text:{KOREA:`어라? 저거 설마?`,JPN:`うん？　あれはまさか？`,ENG:`Err? Is that...`,TWN:`咦？那個難道是？`},stage:{bg:`SUMMER_BEACH_NIGHT`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_SUMMER_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};